import com.atlassian.jira.component.ComponentAccessor
import com.atlassian.jira.issue.link.IssueLinkManager

IssueLinkManager issueLinkManager = ComponentAccessor.getIssueLinkManager()
def customFieldManager = ComponentAccessor.getCustomFieldManager()
def commentManager = ComponentAccessor.getCommentManager()
def userManager = ComponentAccessor.getUserManager()
def issueManager = ComponentAccessor.getIssueManager()

def currentIssue = issue

def linkedIssues = issueLinkManager.getOutwardLinks(currentIssue.id)
if (linkedIssues.size() > 0) {
    def linkedIssue = linkedIssues[0].destinationObject

    def sourceCf = customFieldManager.getCustomFieldObjectByName('Business Impact')
    def targetCf = customFieldManager.getCustomFieldObjectByName('Approval Notes')

    def sourceValue = linkedIssue.getCustomFieldValue(sourceCf)
    currentIssue.setCustomFieldValue(targetCf, sourceValue)

    def user = userManager.getUserByName('admin')
    commentManager.create(currentIssue, user, 'Approval Notes copied from linked issue ' + linkedIssue.key, true)

    issueManager.updateIssue(user, currentIssue, com.atlassian.jira.event.type.EventDispatchOption.DO_NOT_DISPATCH, false)
}
